class AbstractAgent(Generic[AgentDepsT, OutputDataT], ABC):
    """Abstract superclass for Agent, WrapperAgent, and custom agent implementations."""

    @property
    @abstractmethod
    def deps_type(self) -> type:
        """The type of dependencies used by the agent."""
        raise NotImplementedError

    @property
    @abstractmethod
    def output_type(self) -> OutputSpec[OutputDataT]:
        """The type of data output by agent runs."""
        raise NotImplementedError

async def run(self, user_prompt: str, ...) -> AgentRunResult[OutputDataT]:
    # 异步执行的核心逻辑
    async with self.iter(...) as agent_run:
        # 驱动执行流程
        return agent_run.result

def run_sync(self, user_prompt: str, ...) -> AgentRunResult[OutputDataT]:
    # 同步版本包装异步实现
    return _utils.get_event_loop().run_until_complete(
        self.run(user_prompt, ...)
    )

@contextmanager
def override(self, *, name: str = ..., deps: AgentDepsT = ...):
    """临时覆盖代理配置的上下文管理器"""
    # 保存原始配置
    original_name = self.name
    # 应用新配置
    self.name = name
    try:
        yield
    finally:
        # 恢复原始配置
        self.name = original_name

@staticmethod
@contextmanager
def parallel_tool_call_execution_mode(mode: str):
    """设置工具调用的并行执行模式"""
    with ToolManager.parallel_execution_mode(mode):
        yield
